function worked_http_server_ts_postgres_pools_transactions_2(clientAcquired: boolean, statementsSucceeded: boolean, commitKnown: boolean): { outcome: string; release: boolean; retry: boolean } {
  if (!clientAcquired) return { outcome: "pool-unavailable", release: false, retry: true };
  if (!statementsSucceeded) return { outcome: "rollback", release: true, retry: false };
  if (!commitKnown) return { outcome: "ambiguous-commit", release: true, retry: false };
